#include <bits/stdc++.h>
#define int long long
#define ull unsigned long long
#define mk make_pair
#define PII pair<int,int>
#define NoAns puts("-1");
#define FOR(i,j,k) for(int i=(j);i<=(k);++i)
#define ROF(i,j,k) for(int i=(j);i>=(k);--i)
#define FOI(a,b) for(auto a : b)
#define Yes puts("Yes");
#define No puts("No");
#define llinf 0x3f3f3f3f3f3f3f3f
#define inf 0x3f3f3f3f
#define ll long long
#define snd second
#define fst first
#define il inline
#define pb push_back
#define CI const int
#define cl(x) memset(x,0,sizeof x)
#define cli(x) memset(x,0x3f,sizeof x)
#define lowbit(x) (x&(-x))
#define wh while
#define gc() getchar()
#define pc(x) putchar(x)
#define NP namespace
#define ls (k<<1)
#define rs (k<<1|1)
#define mid ((l+r)>>1)
using NP std;
NP phigrOS
{
    il ll read()
    {
        ll x=0,f=1;char ch=gc();
        wh(ch<'0'||ch>'9'){if(ch=='-')f=-1;ch=getchar();}
        wh(ch>='0'&&ch<='9'){x=x*10+ch-'0';ch=gc();}
        return x*f;
    }
    void write(ll x)
    {
        if(x<0)pc('-'),x=-x;
        if(x>9)write(x/10);
        pc(x%10+'0');
    }
    void writeln(ll x)
    {
        write(x);
        puts("");
        return;
    }
}
using NP phigrOS;
CI MAXN=1e4+5;
int n,m,d[MAXN][25],st[MAXN][25],k,s;
vector<PII> g[MAXN];
struct node
{
	int di,p,cnt;
	bool operator < (const node & ccf) const
	{
		return di>ccf.di;
	}
};
void dijkstr()
{
	cli(d);
	priority_queue<node> pq;
	pq.push({0,1,0});
	d[1][0]=0;
	wh(pq.size())
	{
		node front=pq.top();
		int di=front.di;
		int p=front.p;
		int cnt=front.cnt;
		pq.pop();
		if(st[p][cnt])continue;
		FOI(u,g[p])
		{
			if(d[u.fst][cnt]>d[p][cnt]+u.snd)
			{
				d[u.fst][cnt]=d[p][cnt]+u.snd;
				pq.push({d[u.fst][cnt],u.fst,cnt});
			}
			if(cnt>=k)continue;
			if(d[u.fst][cnt+1]>d[p][cnt]+u.snd/2)
			{
				d[u.fst][cnt+1]=d[p][cnt]+u.snd/2;
				pq.push({d[u.fst][cnt+1],u.fst,cnt+1});
			}
		}
	} 
}
signed main(void)
{

    //freopen(".in","r",stdin);
    //freopen(".out","w",stdout);
	ios::sync_with_stdio(0);
	cin.tie(0);
	cout.tie(0);
	cin>>n>>m>>k;
	FOR(i,1,m)
	{
		int u,v,w;
		cin>>u>>v>>w;
		g[u].pb(mk(v,w));
		g[v].pb(mk(u,w));
	}
	dijkstr();
	int ans=llinf;
	FOR(i,0,k)
	{
		ans=min(ans,d[n][i]); 
	}
	cout<<ans;
    return false;
}
